%[text] # 동영상
% basic plot 1

y = [ 2 4 3 6 ];

figure(1); %[output:72a5432f]

plot(y); %[output:72a5432f]
%%
%E.G. 5-1 Joining Circles 
t = 0 : 0.1 : 2 * pi + 0.1; %angle +0.1은 혹시 부족할까봐 1x64 
N = length(t); %이후 행렬 사이즈 맞추기위해서 t의 크기 64 
xone = cos(t'); %cosx = 밑변/빗변(반지름 1이라 가정) 64x1 
y = sin(t'); %sinx = 높이/빗변(반지름 1이라 가정) 64x1 

c = -5.5 : 5.5; %center of circle 1x12 
C = repmat(c, N,1); %1x12 .* 64x1 -> 64x12 
r = abs(c); %radius of the circle 1x12 

X = xone * r + C; %64x12 
Y = y * r; %64x12 
plot(X, Y); %[output:3c1cec47]
%%
xone = [4 3 5 4 3 2 6 4 2 1 3 2 1 0 8 7 6 5 7 4];
y = [4 3 3 2 3 2 2 0 2 1 1 0 1 0 0 1 0 1 1 4] * sqrt(3);
plot(xone, y); %[output:03da7404]
%%
xone = [4 3 4 5 4 3 2 6 5 7 6 2 1 3 2 0 8 4];
y = [4 3 2 3 3 3 2 2 1 1 0 0 1 1 2 0 0 4] * sqrt(3);
plot(xone, y); %[output:028c5854]
%%
%square_spiral 
clear;

x0 = 1: 20; 
x1 = x0 .* ((-1) .^ (x0 + 1)); % -1을 (x0+1) 점 제곱 -> 짝수에만 -부호 추가 이후 x0에 점 곱
x2 = reshape(repmat(x1, 2, 1), 1, []); %x1을 2행 1열로 반복해서 같은 내용을 두 줄 -> 다시 1행으로 만들기(열로 읽는다)
xone = [0 x2]; % 0부터 시작

y0 = 2 : 2: 20; %1x10이다. x0는 1x20
y1 = reshape(repmat(y0, 2, 1), 1, []); %y1을 2행 1열로 반복해서 같은 내용을 두 줄 -> 다시 1행으로 만들기(열로 읽는다)
nl = 1:length(y1); %y1의 위치 번호
y2 = y1.* ((-1) .^ (nl + 1)); %-1을 (nl+1) 점 제곱 -> 짝수에만 -부호 추가 이후 nl에 점 곱
y3 = reshape(repmat(y2, 2, 1), 1, []); %y1을 2행 1열로 반복해서 같은 내용을 두 줄 -> 다시 1행으로 만들기(열로 읽는다)
y = [0 0 y3(1:end-1)]; figure(1); % 0 0을 추가하고 y3의 마지막 값 뺀 y3
plot(xone, y, 'b-o', 'MarkerFaceColor', 'blue'); %[output:9ce08349]
%%
clear;

x0 = reshape(repmat([1:2:10], 2, 1), 1,[]); %[output:74fd2bb9]
x1 = reshape(repmat([2:2:10], 2, 1), 1,[]);
xone = reshape([x0 ; x1],1,[]);
xone(1:4:20) = 0;
xone(2:4:20) = 0;

x2 = reshape(repmat([0:2:8], 2, 1), 1,[]);
x3 = reshape(repmat([1:2:9], 2, 1), 1,[]);
xtwo = reshape([x2 ; x3],1,[]);
xtwo(3:4:20) = 10;
xtwo(4:4:20) = 10;

x = [xone xtwo];

y0 = reshape(repmat([10:-2:2], 2, 1), 1, []);
y1 =  reshape(repmat([9:-2:1], 2, 1), 1, []);
yone = reshape([y0; y1], 1, []);
yone(3:4:20) = 10;
yone(4:4:20) = 10;

y2 = reshape(repmat([9:-2:1], 2, 1), 1,[]);
y3 = reshape(repmat([8:-2:0], 2, 1), 1,[]);
ytwo = reshape([y2 ; y3],1,[]);
ytwo(1:4:20) = 0;
ytwo(2:4:20) = 0;

y = [yone ytwo];

figure(2); %[output:0a7d51c0]
plot(x, y, 'b-o', 'MarkerFaceColor', 'r'); %[output:0a7d51c0]
%%
clear;

x = [1 2.5 6 3];
y = [2 -1 3 2];

plot(x, y, 'r-.o', 'LineWidth', 2, 'MarkerEdgeColor', 'b');  %[output:6abdcd69]
% x축에 벡터x y축에 벡터y를 넣고 빨간선이 대시와 점선을 섞어가며 선의 굵기는 2로 점의 테두리는 파란색으로 나타낸 그래프를 보여라 
axis([0 7 -2 +4]); %[output:6abdcd69]
