%[text] ## Handles and Properties
%[text] 
%[text] - get() 성질을 알기
%[text] - set() 내용을 바꿀 수 있다
%[text] - gca(Get Current Axis)맨 마지막으로 그린 그래프의 성질을 가져옴 \
%%
%[text] ## Text Formatting
%[text] 
%[text] ### Font
%[text] a{\\bfb}c = 굵게 
%[text] \\fontname{times} = times font로
%[text] a{\\itb}c = italic체
%[text] \\fontsize{12} = font size 12
%[text] \\ita{\\rmb}c = 정자체
%[text] 
%[text] ### Subscript and Superscript
%[text] A^{2-x}+b\_1 
%%
%light intensity
clear;

d = 10 : 0.1 : 22; % 이론치
dd = 10 : 2 : 22; % 실험치

y = 1000 * exp (-0.15 * (d - 10));
yy = 1000 * exp (-0.16 * (dd - 10));

h = plot(d, y, 'b-', dd, yy, 'r-o'); %이론 실선 파랑 / 실험 대시 빨강 %[output:5fd0bdd6]
axis([8 24 0 1200]); %[output:5fd0bdd6]

set(h(1), 'LineWidth', 2); % 이론 %[output:5fd0bdd6]
set(h(2), 'LineWidth', 2); % 실험 %[output:5fd0bdd6]
xlabel('Distance (cm)'); %[output:5fd0bdd6]
ylabel("Intensity (lux)"); %[output:5fd0bdd6]
title('Light Imtensity as a Function of Distance'); %[output:5fd0bdd6]
legend('Theory', 'Experiment'); % 이론 실험 %[output:5fd0bdd6]
grid; %[output:5fd0bdd6]
%%
%[text] ## Mission 3
%light intensity

d = 10 : 0.1 : 22; % 이론치
dd = 10 : 2 : 22; % 실험치

y = 1000 * exp (-0.15 * (d - 10));
yy = 1000 * exp (-0.16 * (dd - 10));

h = plot(d, y, 'b-', dd, yy, 'r-.o'); %이론 실선 파랑 / 실험 대시 빨강 %[output:2fe09ddb]
axis ([8 24 0 1200]); %[output:2fe09ddb]

set(h(1), 'LineWidth', 2); % 이론 %[output:2fe09ddb]
set(h(2), 'LineWidth', 2); % 실험 %[output:2fe09ddb]
xlabel('Distance (cm)','FontSize', 16); %[output:2fe09ddb]
xticks([10 14 16 20 22]); %[output:2fe09ddb]
xticklabels({'Start','P1','P2','Edge','End'}); %[output:2fe09ddb]
ylabel("Intensity (lux)"); %[output:2fe09ddb]
title('{\bfL\fontsize{18}}ight {\bfI\fontsize{18}}ntensity \fontsize{16}'); %[output:2fe09ddb]
legend('Theory', 'Experiment'); % 이론 실험 %[output:2fe09ddb]
annotation('textarrow', [0.3 0.5], [0.6 0.4], 'theorectical curve 1000x e^{-0.15(\Gamma - 10)}', 'Peak'); %[output:2fe09ddb] %[output:277112e7]
grid;
